.shc {
  position: relative;
  width: 100%;
  padding: 0 7vw;
}

.shc__desktop {
  position: relative;
  width: var(--stack-width);
  height: var(--stack-height);
  margin: 0 auto;
}

.shc__mobile {
  display: none;
}

.shc__card {
  position: absolute;
  top: 0;
  left: 0;
  width: var(--card-width);
  height: var(--card-height);
  display: flex;
  flex-direction: column;
  justify-content: space-between;
  overflow: hidden;
  border: 1px solid rgba(0, 0, 0, 0.1);
  border-radius: 24px;
  padding: 24px;
  cursor: pointer;
  transform-origin: center center;
  user-select: none;
  will-change: transform;
}

.shc__card--static {
  position: relative;
  width: 100%;
  height: auto;
  min-height: 260px;
  border-radius: 18px;
  transform: none !important;
  transition: none !important;
  cursor: default;
}

.shc__body {
  position: relative;
  z-index: 2;
  display: flex;
  flex: 1;
  align-items: center;
}

.shc__quote {
  max-width: 92%;
  margin: 0;
  font-size: 1.9rem;
  line-height: 0.95;
  letter-spacing: -0.05em;
}

.shc__footer {
  position: relative;
  z-index: 2;
}

.shc__divider {
  width: 100%;
  height: 1px;
  margin-bottom: 1rem;
  background: rgba(0, 0, 0, 0.2);
}

.shc__footer-row {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 1rem;
}

.shc__explore-wrap {
  display: flex;
  align-items: center;
  gap: 0.5rem;
}

.shc__explore-icon {
  display: flex;
  height: 2.25rem;
  width: 2.25rem;
  align-items: center;
  justify-content: center;
  border: 1px solid rgba(0, 0, 0, 0.1);
  border-radius: 999px;
  background: #000;
  color: #fff;
  font-size: 0.9rem;
}

.shc__explore-text {
  font-size: 12px;
  font-weight: 600;
  letter-spacing: 0.14em;
  text-transform: uppercase;
}

.shc__index {
  font-size: 11px;
  letter-spacing: 0.16em;
  opacity: 0.7;
  text-transform: uppercase;
}

@media (max-width: 1024px) {
  .shc__desktop {
    display: none;
  }

  .shc__mobile {
    display: flex;
    flex-direction: column;
    gap: 1rem;
  }

  .shc__card--static {
    padding: 22px;
    border-radius: 22px;
  }

  .shc__quote {
    max-width: 100%;
    font-size: 1.55rem;
    line-height: 1;
  }
}

"use client";

import { useMemo, useState } from "react";
import "./hover-stack.css";

const PRESET_ROTATIONS = [-8, 4, -3, 5, -4, 6, 3, -6, 2, -5];

export default function HoverStack({
  cards = [],
  cardWidth = 280,
  cardHeight = 360,
  overlap = 92,
  hoverLift = 28,
  pushDistance = 110,
  className = "",
}) {
  const [activeIndex, setActiveIndex] = useState(null);

  const preparedCards = useMemo(
    () =>
      cards.map((card, index) => ({
        ...card,
        rotation:
          PRESET_ROTATIONS[index % PRESET_ROTATIONS.length] + (index % 2 === 0 ? 0 : 1),
        baseX: index * overlap,
        baseZ: index + 1,
      })),
    [cards, overlap]
  );

  const totalWidth =
    preparedCards.length > 0 ? preparedCards.at(-1).baseX + cardWidth : cardWidth;

  const getCardStyle = (card, index) => {
    const isActive = activeIndex === index;
    const hasActive = activeIndex !== null;

    let x = card.baseX;
    let y = 0;
    let rotate = card.rotation;
    let zIndex = card.baseZ;
    let scale = 1;

    if (hasActive) {
      if (index < activeIndex) x -= pushDistance;
      if (index > activeIndex) x += pushDistance;

      if (isActive) {
        x = card.baseX;
        y = -hoverLift;
        rotate = 0;
        zIndex = 999;
        scale = 1.035;
      }
    }

    const transition = isActive
      ? "transform 480ms cubic-bezier(0.22, 1.6, 0.32, 1), box-shadow 900ms cubic-bezier(0.22, 1.6, 0.32, 1)"
      : hasActive
        ? "transform 700ms cubic-bezier(0.22, 1, 0.36, 1), box-shadow 700ms cubic-bezier(0.22, 1, 0.36, 1)"
        : "transform 480ms cubic-bezier(0.4, 0, 0.2, 1), box-shadow 380ms cubic-bezier(0.4, 0, 0.2, 1)";

    return {
      "--card-width": `${cardWidth}px`,
      "--card-height": `${cardHeight}px`,
      transform: `translate3d(${x}px, ${y}px, 0) rotate(${rotate}deg) scale(${scale})`,
      zIndex,
      transition,
      background: card.bg,
    };
  };

  return (
    <div className={`shc ${className}`}>
      <div
        className="shc__desktop"
        style={{
          "--stack-width": `${totalWidth}px`,
          "--stack-height": `${cardHeight + hoverLift + 24}px`,
        }}
      >
        {preparedCards.map((card, index) => (
          <div
            key={card.id ?? index}
            className={`shc__card ${card.accent || ""}`}
            style={getCardStyle(card, index)}
            onMouseEnter={() => setActiveIndex(index)}
            onMouseLeave={() => setActiveIndex(null)}
          >
            <div className="shc__body">
              <p className="shc__quote">“{card.quote}”</p>
            </div>
            <div className="shc__footer">
              <div className="shc__divider" />
              <div className="shc__footer-row">
                <div className="shc__explore-wrap">
                  <div className="shc__explore-icon">↗</div>
                  <span className="shc__explore-text">Explore</span>
                </div>
                <div className="shc__index">0{index + 1}</div>
              </div>
            </div>
          </div>
        ))}
      </div>

      <div className="shc__mobile">
        {cards.map((card, index) => (
          <div
            key={card.id ?? index}
            className={`shc__card shc__card--static ${card.accent || ""}`}
            style={{ background: card.bg }}
          >
            <div className="shc__body">
              <p className="shc__quote">“{card.quote}”</p>
            </div>
            <div className="shc__footer">
              <div className="shc__divider" />
              <div className="shc__footer-row">
                <div className="shc__explore-wrap">
                  <div className="shc__explore-icon">↗</div>
                  <span className="shc__explore-text">Explore</span>
                </div>
                <div className="shc__index">0{index + 1}</div>
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}
